void solve(int CASE)
{
	int n; cin >> n;
	string s, t; cin >> s >> t; s = ' ' + s, t = ' ' + t;
	var p = vector<int>(2 * n + 1);
	int j[2] = { 1,1 };
	fa(i, 1, 2 * n) {
		char now;
		if (i & 1)now = s[j[0]++];
		else now = t[j[1]++];

		if (now == 'P')p[i] = 0;
		else if (now == 'W')p[i] = 1;
		else p[i] = 2;
	}
	var w = Vec2<vector<int>>(3, 3);
	int cnt[3] = { 0,0,0 };

	bool no = 0;
	int fin = 2 * n;
	fa(i, 1, 2 * n) {
		cnt[p[i]]++;
		if (i % 3 == 0) {
			var t = vector<int>();
			fa(i, 0, 2)t.pb(cnt[i]);
			sort(all(t));
			if (t[0] == t[1] and t[1] == t[2]) {
				if (!no and (i & 1)) {
					cout << 0 << endl;
					return;
				}
				else {
					no = 1;
					fin = min(fin, i - 1);
				}
			}
			if (t[0] + 1 == t[1] and t[1] + 1 == t[2]) {
				if (cnt[0] == t[0] and cnt[1] == t[2])w[0][1].pb(i);
				else if (cnt[0] == t[0] and cnt[2] == t[2])w[0][2].pb(i);
				else if (cnt[1] == t[0] and cnt[0] == t[2])w[1][0].pb(i);
				else if (cnt[1] == t[0] and cnt[2] == t[2])w[1][2].pb(i);
				else if (cnt[2] == t[0] and cnt[0] == t[2])w[2][0].pb(i);
				else if (cnt[2] == t[0] and cnt[1] == t[2])w[2][1].pb(i);
			}
		}
	}

	fa(i, 1, min(2 * n, fin)) {
		fa(j, 0, 2)if (w[j][p[i]].size()) {
			var it = lower_bound(all(w[j][p[i]]), i);
			if (it == w[j][p[i]].end())continue;
			if ((*it) & 1) {
				cout << 1 << endl;
				return;
			}
		}
	}
	cout << 2 << endl;
	return;
}
